/// Default tag set used when the caller doesn't override.
pub const DEFAULT_TAGS: &[&str] = &[
    "task", "project", "person", "meeting", "research", "idea", "followup", "blocked", "review",
    "weekly",
];

/// Generate a fragment of N words of lorem-style text.
pub fn words(rng: &mut FixtureRng, n: usize) -> String {
    let mut out = String::with_capacity(n * 6);
    for i in 0..n {
        if i > 0 {
            out.push(' ');
        }
        out.push_str(pick(rng, WORDS));
    }
    out
}

/// Render a single block line at the requested indent. Block has:
/// - 4-12 words of body text
/// - 0-2 wikilinks (each is `[[<target>]]`)
/// - 0-1 inline tags (`#tagname`)
pub fn block_line(
    rng: &mut FixtureRng,
    indent: usize,
    note_titles: &[String],
    tags: &[String],
) -> String {
    let mut out = String::new();
    for _ in 0..indent {
        out.push_str("  ");
    }
    out.push_str("- ");
    let n = range(rng, 4, 12);
    out.push_str(&words(rng, n));

    // 35% chance of a wikilink to another note.
    if !note_titles.is_empty() && chance(rng, 0.35) {
        out.push(' ');
        out.push_str("[[");
        out.push_str(pick(rng, note_titles));
        out.push_str("]]");
    }
    // 20% chance of an inline tag.
    if !tags.is_empty() && chance(rng, 0.20) {
        out.push_str(" #");
        out.push_str(pick(rng, tags));
    }
    out
}

/// Render a task block with status / optional deadline / optional
/// priority. Tasks are rendered as a parent block + 1-3 property
/// child blocks (mirrors how Logseq/Tesela actually structure tasks).
pub fn task_block(
    rng: &mut FixtureRng,
    indent: usize,
    note_titles: &[String],
    tags: &[String],
    deadline: Option<&str>,
) -> Vec<String> {
    let mut lines = Vec::with_capacity(4);
    // Parent block: short imperative-sounding text.
    let mut parent = String::new();
    for _ in 0..indent {
        parent.push_str("  ");
    }
    parent.push_str("- ");
    let n = range(rng, 3, 8);
    parent.push_str(&words(rng, n));
    parent.push_str(" #Task");
    lines.push(parent);

    let prop_indent = "  ".repeat(indent + 1);

    // status:: <one of todo/doing/done/backlog>
    let status = pick(rng, &["todo", "doing", "done", "backlog", "todo", "todo"]);
    lines.push(format!("{}status:: {}", prop_indent, status));

    if let Some(d) = deadline {
        lines.push(format!("{}deadline:: [[{}]]", prop_indent, d));
    }

    if chance(rng, 0.3) {
        let pri = pick(rng, &["high", "medium", "low"]);
        lines.push(format!("{}priority:: {}", prop_indent, pri));
    }

    // Maybe a child reference to another note.
    if !note_titles.is_empty() && chance(rng, 0.25) {
        let child_indent = "  ".repeat(indent + 1);
        lines.push(format!(
            "{}- relates to [[{}]]",
            child_indent,
            pick(rng, note_titles)
        ));
    }

    // Maybe a tag hint at the end.
    if !tags.is_empty() && chance(rng, 0.2) {
        let tag_indent = "  ".repeat(indent + 1);
        lines.push(format!("{}- context: #{}", tag_indent, pick(rng, tags)));
    }
    lines
}
